/**
 * Payroll Generator Component
 */

import React, { useState, useEffect } from 'react';
import { toast } from 'react-toastify';
import { FaMoneyBillWave, FaPlay, FaUsers, FaCalendar } from 'react-icons/fa';
import { payrollAPI, employeeAPI } from '../services/api';

function PayrollGenerator() {
  const [loading, setLoading] = useState(false);
  const [generating, setGenerating] = useState(false);
  const [employees, setEmployees] = useState([]);
  const [selectedEmployees, setSelectedEmployees] = useState([]);
  const [salaryMonth, setSalaryMonth] = useState('');
  const [includeBonus, setIncludeBonus] = useState(true);
  const [result, setResult] = useState(null);
  const [salaryRecords, setSalaryRecords] = useState([]);

  // Fetch employees
  useEffect(() => {
    const fetchEmployees = async () => {
      setLoading(true);
      try {
        const response = await employeeAPI.search({ status: 'Active' }, 1, 100);
        setEmployees(response.data.employees);
      } catch (error) {
        toast.error('Failed to fetch employees');
      } finally {
        setLoading(false);
      }
    };
    fetchEmployees();

    // Set default salary month to current month
    const now = new Date();
    const defaultMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`;
    setSalaryMonth(defaultMonth);
  }, []);

  // Fetch existing salary records
  useEffect(() => {
    if (salaryMonth) {
      fetchSalaryRecords();
    }
  }, [salaryMonth]);

  const fetchSalaryRecords = async () => {
    try {
      const response = await payrollAPI.getSalaries(null, salaryMonth, 1, 100);
      setSalaryRecords(response.data.records);
    } catch (error) {
      console.error('Failed to fetch salary records:', error);
    }
  };

  // Handle employee selection
  const handleEmployeeToggle = (empId) => {
    setSelectedEmployees(prev => {
      if (prev.includes(empId)) {
        return prev.filter(id => id !== empId);
      }
      return [...prev, empId];
    });
  };

  const handleSelectAll = () => {
    if (selectedEmployees.length === employees.length) {
      setSelectedEmployees([]);
    } else {
      setSelectedEmployees(employees.map(emp => emp.EmployeeID));
    }
  };

  // Generate payroll
  const handleGeneratePayroll = async () => {
    if (!salaryMonth) {
      toast.error('Please select a salary month');
      return;
    }

    setGenerating(true);
    setResult(null);

    try {
      const response = await payrollAPI.generatePayroll({
        employee_ids: selectedEmployees.length > 0 ? selectedEmployees : null,
        salary_month: salaryMonth,
        include_bonus: includeBonus,
      });

      setResult(response.data);
      toast.success(response.data.message);
      fetchSalaryRecords();
    } catch (error) {
      toast.error('Failed to generate payroll');
      console.error(error);
    } finally {
      setGenerating(false);
    }
  };

  return (
    <div>
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-card-icon" style={{ background: '#bee3f8' }}>
            <FaUsers style={{ color: '#2b6cb0' }} />
          </div>
          <div className="stat-card-value">{employees.length}</div>
          <div className="stat-card-label">Active Employees</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon" style={{ background: '#c6f6d5' }}>
            <FaMoneyBillWave style={{ color: '#276749' }} />
          </div>
          <div className="stat-card-value">{salaryRecords.length}</div>
          <div className="stat-card-label">Payroll Records (This Month)</div>
        </div>
      </div>

      <div className="card">
        <div className="card-header">
          <h2>
            <FaMoneyBillWave style={{ marginRight: '8px' }} />
            Generate Payroll
          </h2>
        </div>
        <div className="card-body">
          {/* Payroll Settings */}
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">
                <FaCalendar style={{ marginRight: '8px' }} />
                Salary Month
              </label>
              <input
                type="date"
                className="form-control"
                value={salaryMonth}
                onChange={(e) => setSalaryMonth(e.target.value)}
              />
            </div>
            <div className="form-group">
              <label className="form-label">Options</label>
              <label style={{ display: 'flex', alignItems: 'center', gap: '8px', marginTop: '8px' }}>
                <input
                  type="checkbox"
                  checked={includeBonus}
                  onChange={(e) => setIncludeBonus(e.target.checked)}
                />
                Include overtime bonus & deductions
              </label>
            </div>
          </div>

          {/* Employee Selection */}
          <div className="form-group">
            <label className="form-label">
              <FaUsers style={{ marginRight: '8px' }} />
              Select Employees ({selectedEmployees.length} selected)
            </label>
            <div style={{ marginBottom: '12px' }}>
              <button className="btn btn-sm btn-secondary" onClick={handleSelectAll}>
                {selectedEmployees.length === employees.length ? 'Deselect All' : 'Select All'}
              </button>
            </div>
            <div style={{ 
              maxHeight: '300px', 
              overflowY: 'auto', 
              border: '1px solid #e2e8f0', 
              borderRadius: '8px',
              padding: '12px'
            }}>
              {loading ? (
                <div className="loading">
                  <div className="spinner"></div>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '8px' }}>
                  {employees.map((emp) => (
                    <label
                      key={emp.EmployeeID}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '8px',
                        padding: '8px',
                        borderRadius: '6px',
                        cursor: 'pointer',
                        background: selectedEmployees.includes(emp.EmployeeID) ? '#ebf8ff' : 'transparent'
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={selectedEmployees.includes(emp.EmployeeID)}
                        onChange={() => handleEmployeeToggle(emp.EmployeeID)}
                      />
                      <span>{emp.FullName}</span>
                      <span style={{ color: '#718096', fontSize: '0.85rem' }}>
                        ({emp.DepartmentName || 'No Dept'})
                      </span>
                    </label>
                  ))}
                </div>
              )}
            </div>
            <p style={{ marginTop: '8px', color: '#718096', fontSize: '0.85rem' }}>
              Leave empty to generate for all active employees
            </p>
          </div>

          {/* Generate Button */}
          <button
            className="btn btn-success"
            onClick={handleGeneratePayroll}
            disabled={generating}
            style={{ marginTop: '16px' }}
          >
            <FaPlay />
            {generating ? 'Generating...' : 'Generate Payroll'}
          </button>

          {/* Results */}
          {result && (
            <div style={{ marginTop: '24px' }}>
              <h3 style={{ marginBottom: '16px' }}>Generation Results</h3>
              <div className="alert alert-info">
                <FaInfoCircle />
                <span>{result.message}</span>
              </div>
              <div className="table-container">
                <table className="table">
                  <thead>
                    <tr>
                      <th>Employee ID</th>
                      <th>Name</th>
                      <th>Status</th>
                      <th>Net Salary</th>
                      <th>Note</th>
                    </tr>
                  </thead>
                  <tbody>
                    {result.details.map((detail, index) => (
                      <tr key={index}>
                        <td>{detail.employee_id}</td>
                        <td>{detail.employee_name}</td>
                        <td>
                          <span className={`badge ${
                            detail.status === 'success' ? 'badge-success' :
                            detail.status === 'skipped' ? 'badge-warning' : 'badge-danger'
                          }`}>
                            {detail.status}
                          </span>
                        </td>
                        <td>
                          {detail.net_salary ? `$${detail.net_salary.toLocaleString()}` : '-'}
                        </td>
                        <td>{detail.reason || '-'}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Existing Salary Records */}
      {salaryRecords.length > 0 && (
        <div className="card" style={{ marginTop: '24px' }}>
          <div className="card-header">
            <h2>Existing Salary Records for {salaryMonth}</h2>
          </div>
          <div className="card-body">
            <div className="table-container">
              <table className="table">
                <thead>
                  <tr>
                    <th>Employee</th>
                    <th>Base Salary</th>
                    <th>Bonus</th>
                    <th>Deductions</th>
                    <th>Net Salary</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {salaryRecords.map((record) => (
                    <tr key={record.salary_id}>
                      <td>{record.employee_name}</td>
                      <td>${record.base_salary?.toLocaleString()}</td>
                      <td style={{ color: '#38a169' }}>+${record.bonus?.toLocaleString()}</td>
                      <td style={{ color: '#e53e3e' }}>-${record.deductions?.toLocaleString()}</td>
                      <td><strong>${record.net_salary?.toLocaleString()}</strong></td>
                      <td>
                        <span className={`badge ${
                          record.status === 'Paid' ? 'badge-success' : 'badge-warning'
                        }`}>
                          {record.status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Add missing import
const FaInfoCircle = ({ style }) => (
  <svg style={style} fill="currentColor" viewBox="0 0 20 20" width="16" height="16">
    <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
  </svg>
);

export default PayrollGenerator;
